const rawInput = $json.body ?? $json;

let input = rawInput;
if (typeof rawInput === 'string') {
  try {
    input = JSON.parse(rawInput);
  } catch (error) {
    input = {};
  }
}

const context =
  input.context && typeof input.context === 'object' && !Array.isArray(input.context)
    ? input.context
    : {};

const DEFAULTS = {
  agent_mode: 'mock',
  max_iterations: 5,
  timeout_minutes: 30,
  manual_approval_required: true,
  action_class: 'read_only',
};

const ACTION_POLICIES = {
  read_only: {
    permission_level: 'read_only',
    requires_human_approval: false,
    forbidden: false,
    reason: 'Read-only analysis may proceed after payload validation.',
  },
  local_draft: {
    permission_level: 'draft',
    requires_human_approval: false,
    approval_recommended: true,
    forbidden: false,
    reason: 'Draft generation is allowed but should remain reviewable.',
  },
  repo_write: {
    permission_level: 'write_action',
    requires_human_approval: true,
    forbidden: false,
    reason: 'Repository write-like actions require explicit human approval before dispatch.',
  },
  shell_command: {
    permission_level: 'forbidden',
    requires_human_approval: true,
    forbidden: true,
    reason: 'Shell command execution is forbidden before a controlled execution adapter exists.',
  },
  git_operation: {
    permission_level: 'forbidden',
    requires_human_approval: true,
    forbidden: true,
    reason: 'Git operations are forbidden before an explicit controlled execution and approval design exists.',
  },
  external_write: {
    permission_level: 'forbidden',
    requires_human_approval: true,
    forbidden: true,
    reason: 'External write actions are forbidden before a controlled execution adapter exists.',
  },
  deployment: {
    permission_level: 'forbidden',
    requires_human_approval: true,
    forbidden: true,
    reason: 'Deployment or production activation is forbidden before controlled execution boundaries are implemented.',
  },
};

const toInteger = (value, fallback) => {
  if (Number.isInteger(value)) return value;

  if (typeof value === 'string' && value.trim() !== '') {
    const parsed = Number(value);
    if (Number.isInteger(parsed)) return parsed;
  }

  return fallback;
};

const normalizeActionClass = (value) =>
  typeof value === 'string'
    ? value.trim().toLowerCase().replace(/[\s-]+/g, '_')
    : '';

const inferActionClassFromGoal = (goalText) => {
  const text = String(goalText || '').toLowerCase();

  if (/\b(git\s+(commit|push|reset|tag|merge|rebase)|commit\s+to\s+git|push\s+to\s+github)\b/.test(text)) {
    return 'git_operation';
  }

  if (/\b(shell|terminal|bash|zsh|run\s+command|execute\s+command|rm\s+-rf|chmod|sudo)\b/.test(text)) {
    return 'shell_command';
  }

  if (/\b(deploy|activate\s+production|publish\s+production|release\s+to\s+prod)\b/.test(text)) {
    return 'deployment';
  }

  if (/\b(send\s+email|post\s+to|update\s+crm|create\s+ticket|external\s+write|write\s+api)\b/.test(text)) {
    return 'external_write';
  }

  if (/\b(modify\s+file|write\s+file|edit\s+repo|change\s+code|apply\s+patch|update\s+workflow\s+json)\b/.test(text)) {
    return 'repo_write';
  }

  if (/\b(draft|proposal|plan|outline)\b/.test(text)) {
    return 'local_draft';
  }

  return DEFAULTS.action_class;
};

const goal = typeof input.goal === 'string' ? input.goal.trim() : '';

const criteria = Array.isArray(input.criteria)
  ? input.criteria.map((item) => String(item).trim()).filter(Boolean)
  : [];

const maxIterations = toInteger(
  input.max_iterations,
  DEFAULTS.max_iterations
);

const timeoutMinutes = toInteger(
  input.timeout_minutes,
  DEFAULTS.timeout_minutes
);

const riskLevel = ['low', 'medium', 'high'].includes(input.risk_level)
  ? input.risk_level
  : ['low', 'medium', 'high'].includes(context.risk_level)
    ? context.risk_level
    : 'low';

const requestedActionClass =
  normalizeActionClass(input.action_class) ||
  normalizeActionClass(context.action_class) ||
  inferActionClassFromGoal(goal);

const actionClass = ACTION_POLICIES[requestedActionClass]
  ? requestedActionClass
  : DEFAULTS.action_class;

const actionPolicy = ACTION_POLICIES[actionClass];
const invalidActionClass = Boolean(requestedActionClass && !ACTION_POLICIES[requestedActionClass]);

const requireHumanApprovalInput =
  typeof input.require_human_approval === 'boolean'
    ? input.require_human_approval
    : typeof input.manual_approval_required === 'boolean'
      ? input.manual_approval_required
      : typeof context.require_human_approval === 'boolean'
        ? context.require_human_approval
        : typeof context.manual_approval_required === 'boolean'
          ? context.manual_approval_required
          : DEFAULTS.manual_approval_required;

const humanApproved = Boolean(input.human_approved || context.human_approved);

const errors = [];

if (!goal) {
  errors.push('goal is required');
}

if (criteria.length === 0) {
  errors.push('criteria must contain at least one item');
}

if (!Number.isInteger(maxIterations) || maxIterations < 1 || maxIterations > 5) {
  errors.push('max_iterations must be an integer between 1 and 5');
}

if (!Number.isInteger(timeoutMinutes) || timeoutMinutes < 1 || timeoutMinutes > 30) {
  errors.push('timeout_minutes must be an integer between 1 and 30');
}

if (invalidActionClass) {
  errors.push('action_class must be one of: ' + Object.keys(ACTION_POLICIES).join(', '));
}

const riskRequiresApproval = ['medium', 'high'].includes(riskLevel);
const actionRequiresApproval = Boolean(actionPolicy.requires_human_approval);
const requiresHumanApproval = Boolean(
  requireHumanApprovalInput || riskRequiresApproval || actionRequiresApproval
);
const forbiddenAction = Boolean(actionPolicy.forbidden);
const requiresApprovalNow =
  !forbiddenAction &&
  errors.length === 0 &&
  (riskRequiresApproval || actionRequiresApproval) &&
  !humanApproved;

const approvalReason = errors.length > 0
  ? 'Request failed payload validation before approval evaluation.'
  : forbiddenAction
    ? actionPolicy.reason
    : requiresApprovalNow
      ? (riskRequiresApproval
          ? 'Medium or high risk action requires explicit human approval before executor dispatch.'
          : actionPolicy.reason)
      : humanApproved && (riskRequiresApproval || actionRequiresApproval)
        ? 'Explicit human approval is present for this gated action.'
        : actionPolicy.reason;

const decision = errors.length > 0
  ? 'invalid_request'
  : forbiddenAction
    ? 'forbidden'
    : requiresApprovalNow
      ? 'needs_human_approval'
      : humanApproved && (riskRequiresApproval || actionRequiresApproval)
        ? 'approved'
        : 'allow';

const approvalDecision = {
  decision,
  risk_level: riskLevel,
  action_class: actionClass,
  permission_level: actionPolicy.permission_level,
  requires_human_approval: requiresHumanApproval,
  approved: humanApproved,
  blocked: ['invalid_request', 'forbidden', 'needs_human_approval'].includes(decision),
  reason: approvalReason,
  approval_required_reason: requiresApprovalNow ? approvalReason : null,
  forbidden_reason: forbiddenAction ? actionPolicy.reason : null,
  approval_package: {
    goal,
    criteria_count: criteria.length,
    risk_level: riskLevel,
    action_class: actionClass,
    permission_level: actionPolicy.permission_level,
    requested_mode: input.provider_mode || input.agent_mode || context.provider_mode || context.agent_mode || DEFAULTS.agent_mode,
    limits: {
      max_iterations: maxIterations,
      timeout_minutes: timeoutMinutes,
    },
    safety_boundaries: [
      'provider output is review material, not execution authority',
      'no file write is enabled',
      'no shell execution is enabled',
      'no Git modification is enabled',
      'no external write action is enabled',
    ],
  },
};

const status = errors.length > 0
  ? 'invalid_request'
  : forbiddenAction
    ? 'forbidden_request'
    : requiresApprovalNow
      ? 'needs_human_approval'
      : 'validated';

return [
  {
    json: {
      goal,
      criteria,
      context,
      agent_mode: input.agent_mode || context.agent_mode || DEFAULTS.agent_mode,
      provider_mode: input.provider_mode || context.provider_mode || undefined,
      provider_execution: input.provider_execution || context.provider_execution || undefined,
      max_iterations: maxIterations,
      timeout_minutes: timeoutMinutes,
      require_human_approval: requiresHumanApproval,
      manual_approval_required: requiresHumanApproval,
      human_approved: humanApproved,
      risk_level: riskLevel,
      action_class: actionClass,
      permission_level: actionPolicy.permission_level,
      validation_errors: errors,
      forbidden_action_detected: forbiddenAction,
      requires_approval_now: requiresApprovalNow,
      approval_decision: approvalDecision,
      status,
    },
  },
];

const now = new Date();
const compactDate = now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14);
const runId = `gd_${compactDate}_${Math.random().toString(36).slice(2, 6)}`;
const taskId = `task_${compactDate}_001`;

return [{
  json: {
    ...$json,
    run_id: runId,
    task_id: taskId,
    iteration: 1,
    instruction: `Work toward the goal and satisfy the criteria: ${$json.goal}`,
    previous_feedback: '',
    requires_human_approval: $json.require_human_approval,
    status: 'initialized'
  }
}];

return [{
  json: {
    ...$json,
    executor_dispatch: {
      target_workflow: 'agent_task_executor.workflow.json',
      workflow_id_placeholder: '{{ $env.N8N_EXECUTOR_WORKFLOW_ID }}',
      transport: 'execute_subworkflow',
      note: 'After import, bind this dispatcher to the imported Agent Task Executor workflow in n8n.'
    },
    status: 'dispatched'
  }
}];

const checks = ($json.criteria || []).map((criterion) => {
  const evidence = ($json.agent_result?.evidence || []).find((item) => item.criterion === criterion);
  return {
    criterion,
    status: evidence?.status || 'unknown',
    evidence: evidence?.detail || 'No evidence provided.'
  };
});
const scoreMap = { pass: 1, unknown: 0.5, fail: 0 };
const score = checks.length === 0
  ? 0
  : checks.reduce((sum, item) => sum + scoreMap[item.status], 0) / checks.length;
const criteriaMet = checks.length > 0 && checks.every((item) => item.status === 'pass');
const canRetry = !criteriaMet && $json.iteration < $json.max_iterations;
const nextInstruction = criteriaMet
  ? null
  : checks
      .filter((item) => item.status !== 'pass')
      .map((item) => `Improve criterion: ${item.criterion}`)
      .join('; ');

return [{
  json: {
    ...$json,
    checker_dispatch: {
      target_workflow: 'criteria_checker.workflow.json',
      workflow_id_placeholder: '{{ $env.N8N_CRITERIA_CHECKER_WORKFLOW_ID }}',
      transport: 'execute_subworkflow',
      note: 'After import, bind this checker call to the imported Criteria Checker workflow in n8n.'
    },
    criteria_result: {
      criteria_met: criteriaMet,
      score: Number(score.toFixed(2)),
      checks,
      next_iteration_instruction: nextInstruction,
      should_stop: !criteriaMet && !canRetry,
      stop_reason: !criteriaMet && !canRetry ? 'max_iterations_reached' : null
    },
    status: criteriaMet
      ? 'completed'
      : canRetry
        ? 'needs_iteration'
        : 'max_iterations_reached'
  }
}];

const input = $json || {};

const agentResult =
  input.agent_result && typeof input.agent_result === 'object'
    ? input.agent_result
    : {};

const criteriaResult =
  input.criteria_result && typeof input.criteria_result === 'object'
    ? input.criteria_result
    : input;

const artifacts = Array.isArray(agentResult.artifacts)
  ? agentResult.artifacts
  : Array.isArray(input.artifacts)
    ? input.artifacts
    : [];

const checks = Array.isArray(criteriaResult.checks)
  ? criteriaResult.checks
  : Array.isArray(input.checks)
    ? input.checks
    : [];

const runId =
  input.run_id ||
  agentResult.run_id ||
  criteriaResult.run_id ||
  `gd_${Date.now()}`;

const taskId =
  input.task_id ||
  agentResult.task_id ||
  criteriaResult.task_id ||
  null;

const iteration =
  Number.isInteger(input.iteration)
    ? input.iteration
    : Number.isInteger(criteriaResult.iteration)
      ? criteriaResult.iteration
      : 1;

const criteriaMet = Boolean(
  input.criteria_met ?? criteriaResult.criteria_met
);

const score =
  typeof input.score === 'number'
    ? input.score
    : typeof criteriaResult.score === 'number'
      ? criteriaResult.score
      : 0;

return [
  {
    json: {
      ...input,
      run_id: runId,
      task_id: taskId,
      status: 'completed',
      criteria_met: criteriaMet,
      iterations: iteration,
      criteria_result: {
        criteria_met: criteriaMet,
        score,
        checks,
        should_stop: Boolean(input.should_stop),
        stop_reason: input.stop_reason ?? null,
        next_iteration_instructions: input.next_iteration_instructions ?? null,
      },
      final_report: {
        summary: criteriaMet
          ? 'All criteria passed in the current mock orchestration run.'
          : 'Criteria were not fully met in the current mock orchestration run.',
        artifacts,
        checks,
      },
      next_action: criteriaMet ? 'stop' : 'revise_and_retry',
    },
  },
];

return [{
  json: {
    run_id: $json.run_id,
    status: $json.status,
    criteria_met: false,
    iterations: $json.iteration,
    next_iteration_instruction: $json.criteria_result.next_iteration_instruction,
    retry_allowed: !$json.criteria_result.should_stop,
    stop_reason: $json.criteria_result.stop_reason,
    next_action: $json.criteria_result.should_stop ? 'finalize_failed_run' : 'dispatch_next_iteration',
    approval_decision: $json.approval_decision || null
  }
}];

const approvalDecision =
  $json.approval_decision && typeof $json.approval_decision === 'object'
    ? $json.approval_decision
    : {
        decision: $json.status === 'needs_human_approval' ? 'needs_human_approval' : 'invalid_request',
        risk_level: $json.risk_level || 'low',
        action_class: $json.action_class || 'read_only',
        permission_level: $json.permission_level || 'read_only',
        requires_human_approval: $json.requires_approval_now || false,
        approved: Boolean($json.human_approved),
        blocked: true,
        reason: 'Request stopped before task initialization.',
      };

return [{
  json: {
    status: $json.status,
    validation_errors: $json.validation_errors || [],
    risk_level: $json.risk_level || approvalDecision.risk_level,
    action_class: $json.action_class || approvalDecision.action_class,
    permission_level: $json.permission_level || approvalDecision.permission_level,
    requires_human_approval: $json.requires_approval_now || approvalDecision.requires_human_approval || false,
    forbidden_action_detected: Boolean($json.forbidden_action_detected),
    approval_decision: approvalDecision,
    note: $json.status === 'needs_human_approval'
      ? 'Manual approval is required before dispatching work.'
      : $json.status === 'forbidden_request'
        ? 'Forbidden action rejected before task initialization.'
        : 'Request rejected before task initialization.'
  }
}];
